// Fetch from source - this is a placeholder
// In production, implement actual fetching logic per source type

const source = $input.first().json;

// For demo: return mock items
// In production: implement RSS/API/scrape logic based on source.fetch_method

const mockItems = [];

// Return structure expected by classifier
return [{
  json: {
    source_id: source.id,
    source_name: source.source_name,
    source_type: source.source_type,
    items: mockItems
  }
}];

// Objection Tracker: Classify raw text into objection events
const input = $input.first().json;

const sourceId = input.source_id;
const sourceName = input.source_name;
const sourceType = input.source_type;
const items = input.items || [];

if (!items.length) {
  return [{ json: { skip: true, reason: 'No items to classify' } }];
}

const systemPrompt = `You are an expert at identifying and classifying buyer objections from customer feedback, reviews, and conversations.

Your task is to analyze text and extract any buyer objections present.

## Objection Categories
- price_value: Cost concerns, ROI unclear, budget issues
- timing: Not the right time, not ready, bad timing
- complexity: Too hard to implement, steep learning curve, integration challenges
- risk: Security concerns, compliance issues, vendor risk
- fit: Doesn't fit needs, wrong solution, feature gaps
- competition: Competitor is better/cheaper, already using alternative
- inertia: Current solution works fine, don't want to change
- authority: Need buy-in from others, not the decision maker
- trust: Don't trust vendor, product quality concerns, reliability worries

## Severity Scale (1-5)
1 = Minor concern, easily addressed
2 = Moderate concern, requires explanation
3 = Significant concern, needs proof/case study
4 = Major concern, potential deal-breaker
5 = Critical concern, likely deal-killer

CRITICAL: Output STRICT JSON only. No markdown code fences.

Output structure:
{
  "classifications": [
    {
      "item_index": 0,
      "objections": [
        {
          "objection_text": "exact objection phrase",
          "category": "price_value|timing|complexity|risk|fit|competition|inertia|authority|trust",
          "severity": 1-5,
          "confidence": 0.0-1.0,
          "persona": "detected persona or null",
          "segment": "detected segment or null",
          "funnel_stage": "awareness|consideration|decision|onboarding|expansion or null",
          "context": "brief context"
        }
      ]
    }
  ]
}`;

const itemsForClassification = items.map((item, idx) => ({
  index: idx,
  text: item.raw_text,
  source: sourceName,
  url: item.source_url || null
}));

const userContent = `Analyze the following ${items.length} text items from "${sourceName}" (${sourceType}) and extract any buyer objections.\n\nItems to analyze:\n${JSON.stringify(itemsForClassification, null, 2)}`;

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4000,
  temperature: 0.1,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    source_id: sourceId,
    source_name: sourceName,
    source_type: sourceType,
    items: items,
    anthropic_body: anthropicBody
  }
}];

// Parse Anthropic classification response
const anthropicResponse = $input.first().json;
const classifyData = $('Classify Objections').first().json;

const sourceId = classifyData.source_id;
const items = classifyData.items;

const content = anthropicResponse.content[0].text;

let classifications;
try {
  const jsonMatch = content.match(/```json?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    classifications = JSON.parse(jsonMatch[1]);
  } else {
    classifications = JSON.parse(content);
  }
} catch (e) {
  throw new Error('Failed to parse: ' + e.message);
}

if (!classifications.classifications || !Array.isArray(classifications.classifications)) {
  throw new Error('Invalid classification response structure');
}

const events = [];
const validCategories = ['price_value', 'timing', 'complexity', 'risk', 'fit', 'competition', 'inertia', 'authority', 'trust'];
const validFunnelStages = ['awareness', 'consideration', 'decision', 'onboarding', 'expansion'];

for (const classification of classifications.classifications) {
  const originalItem = items[classification.item_index];
  if (!originalItem || !classification.objections) continue;

  for (const objection of classification.objections) {
    if (!objection.objection_text || !objection.category) continue;

    const category = validCategories.includes(objection.category) ? objection.category : 'fit';
    const severity = Math.max(1, Math.min(5, Math.round(objection.severity || 3)));
    const confidence = Math.max(0, Math.min(1, objection.confidence || 0.7));
    const funnelStage = validFunnelStages.includes(objection.funnel_stage) ? objection.funnel_stage : null;

    events.push({
      source_id: sourceId,
      external_id: originalItem.external_id || null,
      raw_text: originalItem.raw_text,
      objection_text: objection.objection_text,
      context_text: objection.context || null,
      category: category,
      severity: severity,
      confidence: confidence,
      persona: objection.persona || null,
      segment: objection.segment || null,
      funnel_stage: funnelStage,
      source_url: originalItem.source_url || null,
      source_author: originalItem.source_author || null,
      source_date: originalItem.source_date || null,
      meta: originalItem.meta || {}
    });
  }
}

if (events.length === 0) {
  return [{ json: { skip: true, reason: 'No objections found' } }];
}

return events.map(event => ({ json: event }));

// Compute week range for analysis
const now = new Date();
const dayOfWeek = now.getDay();
const diff = dayOfWeek === 0 ? 6 : dayOfWeek - 1; // Days since Monday

const weekEnd = new Date(now);
weekEnd.setDate(now.getDate() - diff - 1); // Last Sunday
weekEnd.setHours(23, 59, 59, 999);

const weekStart = new Date(weekEnd);
weekStart.setDate(weekEnd.getDate() - 6); // Previous Monday
weekStart.setHours(0, 0, 0, 0);

const formatDate = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    week_start: formatDate(weekStart),
    week_end: formatDate(weekEnd)
  }
}];

// Trend Analysis and Drift Detection
const weekRange = $('Compute Week Range').first().json;
const patternsResult = $('Load & Update Patterns').all();
const prevSnapshotResult = $('Load Previous Snapshot').all();

const weekStart = weekRange.week_start;
const weekEnd = weekRange.week_end;
const patterns = patternsResult.map(r => r.json);
const previousSnapshot = prevSnapshotResult.length > 0 ? prevSnapshotResult[0].json : null;

const patternsToSignal = [];
let driftDetected = false;
let driftSummary = '';

// Identify patterns that warrant signals
for (const pattern of patterns) {
  let signalReason = null;

  // Check for NEW objections (first seen this week)
  const firstSeenDate = new Date(pattern.first_seen_at);
  const weekStartDate = new Date(weekStart);
  if (firstSeenDate >= weekStartDate) {
    signalReason = 'New objection';
  }

  // Check for RISING trends with significant volume
  if (!signalReason && pattern.trend === 'rising' && pattern.count_last_7_days >= 3) {
    signalReason = 'Rising trend';
  }

  // Check for HIGH SEVERITY spikes
  if (!signalReason && pattern.avg_severity >= 4 && pattern.count_last_7_days >= 2) {
    signalReason = 'High severity spike';
  }

  if (signalReason) {
    patternsToSignal.push({
      pattern_id: pattern.id,
      canonical_text: pattern.canonical_text,
      category: pattern.category,
      trend: pattern.trend,
      trend_score: pattern.trend_score,
      count_last_7_days: pattern.count_last_7_days,
      count_last_30_days: pattern.count_last_30_days,
      avg_severity: pattern.avg_severity,
      evidence_urls: pattern.evidence_urls || [],
      signal_reason: signalReason
    });
  }
}

// Sort by priority and cap at 8
patternsToSignal.sort((a, b) => {
  const priorityMap = { 'New objection': 3, 'Rising trend': 2, 'High severity spike': 1 };
  const priorityDiff = (priorityMap[b.signal_reason] || 0) - (priorityMap[a.signal_reason] || 0);
  if (priorityDiff !== 0) return priorityDiff;
  return (b.avg_severity || 0) - (a.avg_severity || 0);
});
const cappedPatterns = patternsToSignal.slice(0, 8);

// Drift Detection
if (previousSnapshot && previousSnapshot.category_counts) {
  const prevCounts = previousSnapshot.category_counts;
  const currentCounts = {};
  for (const pattern of patterns) {
    if (pattern.count_last_7_days > 0) {
      currentCounts[pattern.category] = (currentCounts[pattern.category] || 0) + pattern.count_last_7_days;
    }
  }

  const prevTotal = Object.values(prevCounts).reduce((a, b) => a + b, 0) || 1;
  const currTotal = Object.values(currentCounts).reduce((a, b) => a + b, 0) || 1;
  const significantShifts = [];
  const allCategories = new Set([...Object.keys(prevCounts), ...Object.keys(currentCounts)]);

  for (const category of allCategories) {
    const prevProp = (prevCounts[category] || 0) / prevTotal;
    const currProp = (currentCounts[category] || 0) / currTotal;
    const shift = currProp - prevProp;
    if (Math.abs(shift) > 0.15) {
      significantShifts.push({
        category,
        direction: shift > 0 ? 'increased' : 'decreased',
        magnitude: Math.abs(shift * 100).toFixed(1)
      });
    }
  }

  if (significantShifts.length > 0) {
    driftDetected = true;
    const shiftDescriptions = significantShifts.map(s => `${s.category} ${s.direction} by ${s.magnitude}%`);
    driftSummary = `Objection pattern drift detected: ${shiftDescriptions.join('; ')}`;
  }
}

return [{
  json: {
    week_start: weekStart,
    week_end: weekEnd,
    patterns_to_signal: cappedPatterns,
    total_patterns_analyzed: patterns.length,
    total_signals: cappedPatterns.length,
    drift_detected: driftDetected,
    drift_summary: driftSummary
  }
}];

// Emit signals to control_plane.signals
const input = $input.first().json;

const weekStart = input.week_start;
const weekEnd = input.week_end;
const patternsToSignal = input.patterns_to_signal || [];
const driftDetected = input.drift_detected || false;
const driftSummary = input.drift_summary || '';

const signals = [];

for (const pattern of patternsToSignal) {
  let signalSeverity = Math.round(pattern.avg_severity || 3);
  if (pattern.trend === 'rising') signalSeverity = Math.min(5, signalSeverity + 1);
  if (pattern.signal_reason === 'New objection') signalSeverity = Math.min(5, signalSeverity + 1);

  let title = '';
  switch (pattern.signal_reason) {
    case 'New objection': title = `New objection detected: ${pattern.category}`; break;
    case 'Rising trend': title = `Rising objection trend: ${pattern.category}`; break;
    case 'High severity spike': title = `High-severity objection spike: ${pattern.category}`; break;
    default: title = `Objection signal: ${pattern.category}`;
  }

  const summary = `"${pattern.canonical_text}" - ${pattern.trend} trend with ${pattern.count_last_7_days} occurrences this week (avg severity: ${pattern.avg_severity?.toFixed(1) || 'N/A'})`;
  const evidenceUrls = (pattern.evidence_urls || []).slice(0, 2);

  signals.push({
    signal_type: 'objection',
    severity: signalSeverity,
    confidence: 0.8,
    title: title,
    summary: summary,
    summary_short: pattern.canonical_text.substring(0, 100),
    evidence_urls: evidenceUrls,
    source_schema: 'objection_tracker',
    source_table: 'patterns',
    source_id: pattern.pattern_id,
    decision_type: 'enablement',
    recommended_asset: 'talk_track',
    owner_team: 'sales',
    time_sensitivity: pattern.trend === 'rising' ? 'this_week' : 'monitor',
    meta: JSON.stringify({
      category: pattern.category,
      trend: pattern.trend,
      count_last_7_days: pattern.count_last_7_days,
      signal_reason: pattern.signal_reason,
      week_start: weekStart,
      week_end: weekEnd
    })
  });
}

if (driftDetected && driftSummary) {
  signals.push({
    signal_type: 'objection',
    severity: 4,
    confidence: 0.85,
    title: 'Objection pattern drift detected',
    summary: driftSummary,
    summary_short: 'Significant shift in objection patterns',
    evidence_urls: [],
    source_schema: 'objection_tracker',
    source_table: 'trend_snapshots',
    source_id: 'drift-' + weekStart,
    decision_type: 'positioning',
    recommended_asset: 'deck',
    owner_team: 'PMM',
    time_sensitivity: 'this_week',
    meta: JSON.stringify({ drift_detected: true, drift_summary: driftSummary, week_start: weekStart, week_end: weekEnd })
  });
}

if (signals.length === 0) {
  return [{ json: { skip: true, reason: 'No signals to emit' } }];
}

return signals.map(signal => ({ json: signal }));
